function FriendStatus({ friendId }) {
  const [isOnline, setIsOnline] = useState(null);

  useEffect(() => {
    ChatAPI.subscribeToStatus(friendId, status => setIsOnline(status.isOnline));
    return () => ChatAPI.unsubscribeFromStatus(friendId);
  }, [friendId]);

  return <span>{isOnline ? 'Online' : 'Offline'}</span>;
}

function FriendListItem({ friend }) {
  const [isOnline, setIsOnline] = useState(null);

  useEffect(() => {
    ChatAPI.subscribeToStatus(friend.id, status => setIsOnline(status.isOnline));
    return () => ChatAPI.unsubscribeFromStatus(friend.id);
  }, [friend.id]);

  return (
    <li style={{ color: isOnline ? 'green' : 'black' }}>
      {friend.name}
    </li>
  );
}
